1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const CURSE_SURCHARGE = 0.5;
14	
15	type Item = { type: string; cursed?: boolean };
16	type QuoteStep = { op: "quote"; items: Item[] };
17	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
18	
19	// MHPCO rounds premiums up in its own favor. A float-precision guard avoids
20	// surprises like 197.5 + 0 rendering as 197.5000000001 and rounding to 198
21	// when the true mathematical value was already on an integer boundary.
22	const roundUpInMHPCOFavor = (amount: number): number =>
23	  Math.ceil(Math.round(amount * 1e6) / 1e6);
24	
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	const COMPONENT_BLOCK_SIZE = 3;
27	const COMPONENT_BLOCK_PREMIUM = 60;
28	
29	const componentGroupPremium = (type: string, count: number): number =>
30	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * BASE_PREMIUM[type];
31	
32	type PremiumLine = { base: number; itemSurchargeRate: number };
33	
34	const mainItemLine = (item: Item): PremiumLine => ({
35	  base: BASE_PREMIUM[item.type],
36	  itemSurchargeRate: item.cursed ? CURSE_SURCHARGE : 0,
37	});
38	
39	const itemPremiumLines = (items: Item[]): PremiumLine[] => {
40	  const mainItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
41	  const components = items.filter((item) => COMPONENT_TYPES.has(item.type));
42	  const componentCountsByType = new Map<string, number>();
43	  for (const c of components) {
44	    componentCountsByType.set(c.type, (componentCountsByType.get(c.type) ?? 0) + 1);
45	  }
46	  const mainLines = mainItems.map(mainItemLine);
47	  const componentLines = [...componentCountsByType].map(([type, count]) => ({
48	    base: componentGroupPremium(type, count),
49	    itemSurchargeRate: 0,
50	  }));
51	  return [...mainLines, ...componentLines];
52	};
53	
54	const quoteStep = (step: QuoteStep): { premium: number } => {
55	  const itemTotal = itemPremiumLines(step.items).reduce(
56	    (sum, line) => sum + line.base * (1 + FIRST_INSURANCE_SURCHARGE + line.itemSurchargeRate),
57	    0,
58	  );
59	  const total = itemTotal + PROCESSING_FEE;
60	  return { premium: roundUpInMHPCOFavor(total) };
61	};
62	
63	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
64	  const results = scenario.steps.map(quoteStep);
65	  return { results };
66	};
