const linePremium = (line: PremiumLine): number =>
  line.base * (1 + FIRST_INSURANCE_SURCHARGE + line.itemSurchargeRate);

const quoteStep = (step: QuoteStep): { premium: number } => {
  const itemTotal = itemPremiumLines(step.items)
    .map(linePremium)
    .reduce((sum, p) => sum + p, 0);
  const total = itemTotal + PROCESSING_FEE;
  return { premium: roundUpInMHPCOFavor(total) };
};
